class SideNavbarControls{constructor(){let e=this.closeNav,t=this.openNav;document.getElementById("side-navigation-close-button").onclick=()=>{e()},document.getElementById("side-navigation-open-button").onclick=()=>{t()}}openNav(){document.getElementById("side-navigation").style.width="250px"}closeNav(){document.getElementById("side-navigation").style.width="0"}}export{SideNavbarControls};